  ('dietitian-moex-01457', 'dietitian', 'dietitian-moex-109-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '某餐廳3月份用餐為3,200人次，平均每人消費300元；固定成本為248,600元，變動成本為 480,000元，則其損益平衡點顧客人數約為多少人？', '["772人", "1,544人", "1,658人", "2,429人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:55+00:00", "source_pdf_sha1": "73a0704b25f2", "answer_pdf_sha1": "a8a9e9767cf1", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "103", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
